mapper.select:
SELECT b.board_id as boardId, b.title, b.created_at as createdAt, b.view_count as viewCount, m.nickname as nickName from board b inner join member m ON b.member_id = m.member_id
AND b.is_deleted = 0
and b.board_id = #{boardId}
and b.member_id = #{memberId}
order by b.board_id DESC

mapper.update:
update board 
   set title = #{title}, content = #{content}
where board_id = #{boardId}

mapper.delete:
update board
   set is_deleted = '1'
where board_id = #{boardId}
